import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;

public class FileHandler {

    private static final String BASE_DIR = "/path/to/files/";

    public void readFile(String fileName) {
        Path filePath = Paths.get(BASE_DIR, fileName).normalize();

        if (!filePath.startsWith(Paths.get(BASE_DIR))) {
            System.out.println("Invalid file path.");
            return;
        }

        try {
            byte[] fileData = Files.readAllBytes(filePath);
            String content = new String(fileData);
            System.out.println(content);
        } catch (IOException e) {
            System.out.println("Error reading file: " + e.getMessage());
        }
    }

    public static void main(String[] args) {
        FileHandler fileHandler = new FileHandler();
        fileHandler.readFile("example.txt");
    }
}

